// Aceita tanto o formato de teste (pendencia_id/audio_resumo/nivel_risco)
// quanto o formato de produção (aprovacao_id/descricao/risco)
const d = $input.first().json;

const risco      = d.nivel_risco || d.risco || 'ALTO';
const descricao  = d.audio_resumo || d.descricao || '(sem descrição)';
const aprovId    = d.pendencia_id || d.aprovacao_id || ('HITL-' + Date.now());

const emojis = { 'ALTO': '🔴', 'CRÍTICO': '🚨', 'CRITICO': '🚨' };
const emoji = emojis[risco.toUpperCase()] || '⚠️';

const ts = new Date().toLocaleString('pt-BR', {
  timeZone: 'America/Manaus',
  day: '2-digit', month: '2-digit', year: 'numeric',
  hour: '2-digit', minute: '2-digit',
});

const mensagem =
  `${emoji} *AGENT BASTOS — ALERTA ${risco}*\n\n` +
  `📝 *Descrição:*\n${descricao}\n\n` +
  `🔑 *ID:* ${aprovId}\n` +
  `🕐 *Horário:* ${ts}\n\n` +
  `━━━━━━━━━━━━━━━━━━━━\n` +
  `Responda com:\n` +
  `✅ *CONFIRMAR ${aprovId}* — para aprovar\n` +
  `❌ *REJEITAR ${aprovId}* — para reprovar\n\n` +
  `_Esta aprovação expira em 60 minutos._`;

return [{ json: { aprovacao_id: aprovId, numero_destino: '559281727347', mensagem } }];

// n8n webhook wraps o payload do Evolution como { headers, params, query, body }
// O payload real do Evolution está sempre em raw.body
const raw = $input.first().json;
const payload = raw.body ?? raw;

let aprovacao_id = null;
let decisao = null;

// Texto digitado: CONFIRMAR <id> ou REJEITAR <id>
const texto = (
  payload?.data?.message?.conversation ||
  payload?.data?.message?.extendedTextMessage?.text ||
  payload?.message?.conversation ||
  ''
).trim().toUpperCase();

const match = texto.match(/(CONFIRMAR|REJEITAR)\s+(HITL-\d+|[A-F0-9-]{36})/i);
if (match) {
  decisao = match[1].toLowerCase() === 'confirmar' ? 'confirmada' : 'rejeitada';
  aprovacao_id = match[2];
}

// Botão de resposta (formato Evolution)
const buttonId = payload?.data?.key?.buttonId
  || payload?.data?.message?.buttonsResponseMessage?.selectedButtonId || '';
if (buttonId.startsWith('confirmar_')) {
  aprovacao_id = buttonId.replace('confirmar_', '');
  decisao = 'confirmada';
} else if (buttonId.startsWith('rejeitar_')) {
  aprovacao_id = buttonId.replace('rejeitar_', '');
  decisao = 'rejeitada';
}

if (!aprovacao_id || !decisao) {
  return [{ json: { ignorar: true, motivo: 'Mensagem não relacionada ao HITL' } }];
}

const remetente = payload?.data?.key?.remoteJid || 'whatsapp';
return [{ json: { aprovacao_id, decisao, resposta_por: remetente, observacao: `Respondido via WhatsApp por ${remetente}` } }];

